package com.trademaster.ims.mobile.fulfillment.model;
import jakarta.persistence.*;import java.time.Instant;
@Entity @Table(name="delivery_events",indexes=@Index(name="idx_delivery_event_fulfillment",columnList="fulfillment_id,occurred_at"))public class DeliveryEvent{public enum EventType{PROCESSING,PACKED,SHIPPED,OUT_FOR_DELIVERY,DELIVERED,COD_COLLECTED,COD_RECONCILED,EXCEPTION,NOTE} @Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="fulfillment_id",nullable=false)private Long fulfillmentId;@Enumerated(EnumType.STRING)@Column(name="event_type",nullable=false,length=32)private EventType eventType;@Column(nullable=false,length=160)private String title;@Column(length=700)private String description;@Column(length=160)private String location;@Column(name="customer_visible",nullable=false)private boolean customerVisible=true;@Column(name="occurred_at",nullable=false)private Instant occurredAt;@Column(name="created_at",nullable=false)private Instant createdAt;@PrePersist void p(){Instant n=Instant.now();if(occurredAt==null)occurredAt=n;createdAt=n;}public Long getId(){return id;}public Long getFulfillmentId(){return fulfillmentId;}public void setFulfillmentId(Long v){fulfillmentId=v;}public EventType getEventType(){return eventType;}public void setEventType(EventType v){eventType=v;}public String getTitle(){return title;}public void setTitle(String v){title=v;}public String getDescription(){return description;}public void setDescription(String v){description=v;}public String getLocation(){return location;}public void setLocation(String v){location=v;}public boolean isCustomerVisible(){return customerVisible;}public void setCustomerVisible(boolean v){customerVisible=v;}public Instant getOccurredAt(){return occurredAt;}public void setOccurredAt(Instant v){occurredAt=v;}public Instant getCreatedAt(){return createdAt;}}